import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import NotificationBell from '../components/NotificationBell';
import {
  getSuperadminDashboard, getAllCompanies, registerCompany, updateCompanyStatus,
  getAllAdmins, createAdmin, deleteAdmin,
  getAllRegions, getAnalytics, getChangeRequests, approveChangeRequest, rejectChangeRequest,
  getCompanyClinics, getCompanyAdminsWithRegions,
} from '../api';

const TABS = ['Dashboard', 'Companies', 'Admins', 'Analytics', 'Change Requests'];
const PRIMARY = '#4a148c';

export default function Superadmin() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab]               = useState(0);
  const [stats, setStats]           = useState({});
  const [companies, setCompanies]   = useState([]);
  const [admins, setAdmins]         = useState([]);
  const [regions, setRegions]       = useState([]);
  const [analytics, setAnalytics]   = useState({});
  const [changeReqs, setChangeReqs] = useState([]);
  const [expandedCo, setExpandedCo] = useState(null);
  const [coClinics, setCoClinics]   = useState([]);
  const [coAdmins, setCoAdmins]     = useState([]);
  const [msg, setMsg]               = useState({ text:'', ok:true });

  const [coForm, setCoForm]   = useState({ name:'',email:'',contact:'',registration_number:'',address:'',subscription_plan:'purchase' });
  const [adForm, setAdForm]   = useState({ username:'',email:'',password:'',name:'',contact:'',company_id:'',region_ids:[] });

  useEffect(() => { loadBase(); }, []);

  const loadBase = async () => {
    const [st, co, ad, rg] = await Promise.all([getSuperadminDashboard(), getAllCompanies(), getAllAdmins(), getAllRegions()]);
    setStats(st); setCompanies(co.companies||[]); setAdmins(ad.admins||[]); setRegions(rg.regions||[]);
  };

  const handleTab = async (i) => {
    setTab(i);
    if (i===3) { const a=await getAnalytics(); setAnalytics(a); }
    if (i===4) { const r=await getChangeRequests(); setChangeReqs(r.requests||[]); }
  };

  const flash = (text, ok=true) => { setMsg({text,ok}); setTimeout(()=>setMsg({text:'',ok:true}),4000); };

  const handleExpandCo = async (id) => {
    if (expandedCo===id) { setExpandedCo(null); return; }
    setExpandedCo(id);
    const [cl,ad] = await Promise.all([getCompanyClinics(id), getCompanyAdminsWithRegions(id)]);
    setCoClinics(cl.clinics||[]); setCoAdmins(ad.admins||[]);
  };

  const handleRegisterCo = async (e) => {
    e.preventDefault();
    try { await registerCompany(coForm); flash('Company registered!'); setCoForm({name:'',email:'',contact:'',registration_number:'',address:'',subscription_plan:'purchase'}); loadBase(); }
    catch(err){ flash(err.response?.data?.detail||'Failed',false); }
  };

  const handleToggleCo = async (id, status) => {
    await updateCompanyStatus(id, status==='active'?'inactive':'active');
    flash(`Company ${status==='active'?'deactivated':'activated'}.`); loadBase();
  };

  const handleCreateAdmin = async (e) => {
    e.preventDefault();
    try {
      await createAdmin({...adForm, company_id:parseInt(adForm.company_id), region_ids:adForm.region_ids.map(Number)});
      flash('Admin created!'); setAdForm({username:'',email:'',password:'',name:'',contact:'',company_id:'',region_ids:[]}); loadBase();
    } catch(err){ flash(err.response?.data?.detail||'Failed',false); }
  };

  const handleDeleteAdmin = async (id) => {
    if (!window.confirm('Delete admin?')) return;
    await deleteAdmin(id); flash('Admin deleted.'); loadBase();
  };

  const handleApprove = async (id) => {
    await approveChangeRequest(id); flash('Approved & applied.');
    const r=await getChangeRequests(); setChangeReqs(r.requests||[]);
  };

  const handleReject = async (id) => {
    const reason=prompt('Rejection reason:'); if (!reason) return;
    await rejectChangeRequest(id,reason); flash('Rejected.');
    const r=await getChangeRequests(); setChangeReqs(r.requests||[]);
  };

  const toggleRegion = (id) => setAdForm(f=>({...f, region_ids: f.region_ids.includes(id)?f.region_ids.filter(r=>r!==id):[...f.region_ids,id]}));

  return (
    <div style={s.page}>
      <header style={s.header}>
        <div style={s.hl}><span style={s.logo}>💊 CareLine</span><span style={s.roleTag}>Super Admin</span></div>
        <div style={s.hr}>
          <span style={s.welcome}>{user.name}</span>
          <NotificationBell role="superadmin" userId={user.superadmin_id} />
          <button style={s.logoutBtn} onClick={()=>{logout();navigate('/login');}}>Logout</button>
        </div>
      </header>

      {msg.text && <div style={{...s.flash,background:msg.ok?'#2e7d32':'#c62828'}}>{msg.text}</div>}

      <nav style={s.tabs}>
        {TABS.map((t,i)=><button key={t} style={tab===i?s.tabOn:s.tabOff} onClick={()=>handleTab(i)}>{t}</button>)}
      </nav>

      <main style={s.main}>

        {/* DASHBOARD */}
        {tab===0 && <>
          <div style={s.statGrid}>
            {[['🏢 Companies',stats.total_companies],['👨‍⚕️ Doctors',stats.total_doctors],['🧑‍🤝‍🧑 Patients',stats.total_patients],['📋 Appointments',stats.total_appointments]].map(([l,v])=>(
              <div key={l} style={s.statCard}><div style={s.statVal}>{v??'…'}</div><div style={s.statLbl}>{l}</div></div>
            ))}
          </div>
          <h3>All Companies</h3>
          <DataTable cols={['Company','Clinics','Admins','Plan','Status']}
            rows={companies.map(c=>[c.name,c.clinic_count,c.admin_count,c.subscription_plan,<Chip key={c.id} status={c.status}/>])} />
        </>}

        {/* COMPANIES */}
        {tab===1 && <div style={s.twoCol}>
          <Card title="Register Company">
            <form onSubmit={handleRegisterCo} style={s.col}>
              {['name','email','contact','registration_number','address'].map(k=><F key={k} label={k} val={coForm[k]} set={v=>setCoForm(f=>({...f,[k]:v}))} />)}
              <label style={s.lbl}>Subscription Plan
                <select style={s.inp} value={coForm.subscription_plan} onChange={e=>setCoForm(f=>({...f,subscription_plan:e.target.value}))}>
                  <option value="purchase">Purchase</option>
                  <option value="rental">Rental</option>
                  <option value="per_consultation_with_doctor">Per Consultation (with Doctor)</option>
                  <option value="per_consultation_without_doctor">Per Consultation (without Doctor)</option>
                </select>
              </label>
              <button style={s.btn} type="submit">Register</button>
            </form>
          </Card>
          <div>
            <h3>All Companies</h3>
            {companies.map(c=>(
              <div key={c.id} style={s.listItem}>
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:8}}>
                  <div>
                    <strong>{c.name}</strong>
                    <div style={s.sub}>{c.email} | {c.contact}</div>
                    <div style={s.sub}>{c.subscription_plan} — {c.clinic_count} clinics, {c.admin_count} admins</div>
                  </div>
                  <div style={{display:'flex',gap:6,flexShrink:0,alignItems:'center'}}>
                    <Chip status={c.status}/>
                    <button style={c.status==='active'?s.noBtn:s.okBtn} onClick={()=>handleToggleCo(c.id,c.status)}>
                      {c.status==='active'?'Deactivate':'Activate'}
                    </button>
                    <button style={s.expandBtn} onClick={()=>handleExpandCo(c.id)}>{expandedCo===c.id?'▲':'▼'}</button>
                  </div>
                </div>
                {expandedCo===c.id && (
                  <div style={s.expandPanel}>
                    <strong>Clinics</strong>
                    {coClinics.map(cl=><div key={cl.id} style={s.expandRow}>{cl.name} — {cl.city_name}, {cl.province}</div>)}
                    <strong style={{display:'block',marginTop:8}}>Admins</strong>
                    {coAdmins.map(a=><div key={a.id} style={s.expandRow}>{a.name} — {a.contact}</div>)}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>}

        {/* ADMINS */}
        {tab===2 && <div style={s.twoCol}>
          <Card title="Create Admin">
            <form onSubmit={handleCreateAdmin} style={s.col}>
              {['username','email','password','name','contact'].map(k=><F key={k} label={k} type={k==='password'?'password':'text'} val={adForm[k]} set={v=>setAdForm(f=>({...f,[k]:v}))} />)}
              <label style={s.lbl}>Company
                <select style={s.inp} value={adForm.company_id} onChange={e=>setAdForm(f=>({...f,company_id:e.target.value}))} required>
                  <option value="">Select company</option>
                  {companies.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </label>
              <label style={s.lbl}>Assign Regions
                <div style={s.regionBox}>
                  {regions.map(r=>(
                    <label key={r.region_id} style={s.regionCheck}>
                      <input type="checkbox" checked={adForm.region_ids.includes(r.region_id)} onChange={()=>toggleRegion(r.region_id)} />
                      {r.province} — {r.sub_region}
                    </label>
                  ))}
                </div>
              </label>
              <button style={s.btn} type="submit">Create Admin</button>
            </form>
          </Card>
          <div>
            <h3>All Admins ({admins.length})</h3>
            {admins.map(a=>(
              <div key={a.id} style={s.listItem}>
                <div style={{display:'flex',justifyContent:'space-between'}}>
                  <div>
                    <strong>{a.name}</strong>
                    <div style={s.sub}>{a.company_name} | {a.contact}</div>
                    <div style={s.sub}>
                      {Array.isArray(a.regions)&&a.regions[0]!==null
                        ?a.regions.map(r=>`${r.province}-${r.sub_region}`).join(', ')
                        :'No regions'}
                    </div>
                  </div>
                  <button style={s.noBtn} onClick={()=>handleDeleteAdmin(a.id)}>Delete</button>
                </div>
              </div>
            ))}
          </div>
        </div>}

        {/* ANALYTICS */}
        {tab===3 && <>
          <div style={s.twoCol}>
            <Card title="By Company">
              {(analytics.by_company||[]).map(r=>(
                <div key={r.company} style={s.aRow}>
                  <span style={{minWidth:120,fontSize:'.8rem'}}>{r.company}</span>
                  <div style={s.barWrap}><div style={{...s.bar,width:`${Math.min(100,(r.appointments/300)*100)}%`}}/></div>
                  <span style={s.barVal}>{r.appointments}</span>
                </div>
              ))}
            </Card>
            <Card title="Monthly Trend">
              {(analytics.monthly_trend||[]).map(r=>(
                <div key={r.month} style={s.aRow}>
                  <span style={{minWidth:60,fontSize:'.8rem'}}>{new Date(r.month).toLocaleDateString('en',{month:'short',year:'2-digit'})}</span>
                  <div style={s.barWrap}><div style={{...s.bar,width:`${Math.min(100,(r.appointments/100)*100)}%`,background:'#7b1fa2'}}/></div>
                  <span style={s.barVal}>{r.appointments}</span>
                </div>
              ))}
            </Card>
          </div>
          <Card title="By Region">
            <DataTable cols={['Province','Sub-Region','Appointments']}
              rows={(analytics.by_region||[]).map(r=>[r.province,r.sub_region,r.appointments])} />
          </Card>
        </>}

        {/* CHANGE REQUESTS */}
        {tab===4 && <>
          <h3>Pending Change Requests ({changeReqs.length})</h3>
          {changeReqs.length===0&&<p style={s.empty}>None pending.</p>}
          {changeReqs.map(r=>(
            <div key={r.id} style={s.listItem}>
              <div style={{display:'flex',justifyContent:'space-between',gap:12}}>
                <div>
                  <strong>{r.admin_name}</strong> — {r.company_name}
                  <div style={s.sub}>Type: <strong>{r.request_type}</strong></div>
                  <div style={s.sub}>Data: {r.requested_data}</div>
                  {r.reason&&<div style={s.sub}>Reason: {r.reason}</div>}
                  <div style={s.sub}>{new Date(r.created_at).toLocaleString()}</div>
                </div>
                <div style={{display:'flex',gap:8,flexShrink:0,alignItems:'flex-start'}}>
                  <button style={s.okBtn} onClick={()=>handleApprove(r.id)}>✓ Approve</button>
                  <button style={s.noBtn} onClick={()=>handleReject(r.id)}>✗ Reject</button>
                </div>
              </div>
            </div>
          ))}
        </>}

      </main>
    </div>
  );
}

function Card({title,children}){return <div style={s.card}><h3 style={{marginTop:0}}>{title}</h3>{children}</div>;}
function F({label,type='text',val,set}){return <label style={s.lbl}>{label.charAt(0).toUpperCase()+label.slice(1).replace(/_/g,' ')}<input style={s.inp} type={type} value={val} onChange={e=>set(e.target.value)} required/></label>;}
function Chip({status}){return <span style={{background:status==='active'?'#4caf50':'#f44336',color:'white',borderRadius:12,padding:'2px 9px',fontSize:'.72rem',fontWeight:700}}>{status}</span>;}
function DataTable({cols,rows}){return <div style={{overflowX:'auto'}}><table style={s.table}><thead><tr>{cols.map(c=><th key={c} style={s.th}>{c}</th>)}</tr></thead><tbody>{rows.map((r,i)=><tr key={i}>{r.map((c,j)=><td key={j} style={s.td}>{c}</td>)}</tr>)}</tbody></table></div>;}

